INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Calf Raises', 1, 'Place the bar on your back') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Calf Raises', 2, 'Start with feet flat on the ground') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Calf Raises', 3, 'Extend your heels upwards while keeping your knees stationary, and pause at the contracted position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Calf Raises', 4, 'Slowly return to the starting position. Repeat.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Calf Jump', 1, 'Stand with your feet shoulder-width apart and your knees slightly bent.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Calf Jump', 2, 'Shift your weight onto the balls of your feet and raise stay flat footed. Using your calf muscles, mimic a jumping motion but don''t leave the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Calf Jump', 3, 'Explode onto your tip toes and hold for a second.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Calf Jump', 4, 'Bring your heels back to the floor then initiate the next rep.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Seated Calf Raise', 1, 'Start by sitting on a bench with a barbell resting on your knees. Your feet should be flat on the ground, about hip-width apart.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Seated Calf Raise', 2, 'Place your hands on the barbell for support, and lift your heels off the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Seated Calf Raise', 3, 'Hold this position for a moment, then slowly lower your heels back to the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Toes Up Calf Raise', 1, 'Begin by standing on a raised surface (such as a step or box) with the balls of your feet on the edge of the surface and your heels hanging off. Hold a barbell across your upper back and shoulders, using an overhand grip.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Toes Up Calf Raise', 2, 'Keeping your core engaged and your back straight, push through the balls of your feet to raise your heels up as high as you can.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Toes Up Calf Raise', 3, 'Lower your heels back down to the starting position, allowing your calves to stretch.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Calf Raise', 1, 'Stand facing the barbell, holding the end of the barbell close to your chest in both hands with your elbows tucked in to your sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Calf Raise', 2, 'Drive though the balls of your feet to raise your heels off the ground, squeezing your calves, with a focus on making sure your ankles do not turn out or in.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Calf Raise', 3, 'Lower your heels back down to the ground and repeat for the desired number of reps.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Calf Raise', 1, 'Stand tall with your feet on the ground. You can put the the balls of your feet on top of a plate to extend the range of motion.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Calf Raise', 2, 'Imagine you have a string attached to your heels and pull your heels up toward the ceiling.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Seated Calf Raise', 1, 'Start by sitting on a bench with your feet shoulder-width apart and a dumbbell in each hand placed on each leg.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Seated Calf Raise', 2, 'From this starting position, raise your heels as high as you can by pushing up through your toes.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Seated Calf Raise', 3, 'Slowly lower your heels back down to the starting position, and repeat for the desired number of repetitions.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Single Leg Calf Raise', 1, 'Standing straight with a dumbbell in one hand, lift the same foot as the side without the dumbbell off the floor. Hold onto something for balance.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Single Leg Calf Raise', 2, 'Raise your heel upwards while keeping your knees stationary.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Single Leg Calf Raise', 3, 'Pause when your heels are fully extended and then slowly return to the starting position and repeat.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Walking Calf Raises', 1, 'Walk forward and push your toe into the ground') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Walking Calf Raises', 2, 'Lift you heel off the ground each step and tense your calf muscle') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Walking Calf Raises', 3, 'Repeat on each leg and walk forward slowly') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Tip Toe Walking', 1, 'Point your toes into the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Tip Toe Walking', 2, 'Slowly walk forwards and backward') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Tip Toe Walking', 3, 'Keep your heels in the air as long as possible while walking.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Tip Toe Walking', 4, 'It may be beneficial to do this last at the end of your workout.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Calf Raises', 1, 'Balance on the balls of your feet on the platform or plates, leaning forward to use the wall to assist with balance.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Calf Raises', 2, 'Lower the heels of your feet towards the ground and pause, then push through the balls of your feet like you are standing tip toe, pausing at the apex of the motion.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Calf Raises', 3, 'Repeat as necessary.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Bodyweight Donkey Calf Raise', 1, 'Hold on to something for balance.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Bodyweight Donkey Calf Raise', 2, 'Hinge forward and maintain that position. Calf raise until you feel a contraction in your calfs.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Bodyweight Single Leg Calf Raise', 1, 'Hold onto something for balance. Raise one foot off the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Bodyweight Single Leg Calf Raise', 2, 'Raise your heel upwards while keeping your knees stationary.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Bodyweight Single Leg Calf Raise', 3, 'Pause when your heels are fully extended and then slowly return to the starting position and repeat.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Machine Seated Calf Raises', 1, 'Get comfortable on the machine, then place your lower thighs beneath the padded lever. Place your toes and the balls of your feet onto the foot supports.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Machine Seated Calf Raises', 2, 'Prevent the weight from slipping forward by gripping the handles, and release the safety bar. Lower the weight until your calves are extended.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Machine Seated Calf Raises', 3, 'Push your heels up to lift the padded lever and hold the contracted position, then slowly lower back down to the starting position. Repeat.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Machine Standing Calf Raises', 1, 'Adjust the machine in accordance with your height and place your shoulders underneath the padded lever.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
