INSERT INTO step (workout_name, step_number, step_description) VALUES ('Stair Climber', 2, 'Drive through midfoot, alternate steps smoothly, avoid leaning heavily on handles.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
