INSERT INTO step (workout_name, step_number, step_description) VALUES ('Treadmill Walk', 1, 'Get the treadmill up to a comfortable speed where you are doing a walk.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Toe Tap', 1, 'Stand in front of a low box.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Toe Tap', 2, 'Bring one foot to the edge of the box and alternate as quickly as possible.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Toe Tap', 3, 'Only lightly tap your feet to the box.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Treadmill Backwards Walk', 1, 'Face the opposite direction on the treadmill.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Treadmill Backwards Walk', 2, 'Hold on to the arms to find your balance.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Treadmill Backwards Walk', 3, 'Walk backwards pushing your toes through the front of your shoes.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Treadmill Side Shuffle', 1, 'Face sideways on the treadmill.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Treadmill Side Shuffle', 2, 'Take a quarter squat position with a wide stance.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Treadmill Side Shuffle', 3, 'Shuffle sideways for a specified amount of time, then switch sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Seated Calf Raise', 1, 'Start by sitting on a bench or box with the bar resting on your knees. Your feet should be flat on the ground, about hip-width apart.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Seated Calf Raise', 2, 'Place your hands on the barbell for support, and lift your heels off the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Seated Calf Raise', 3, 'Hold this position for a moment, then slowly lower your heels back to the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Calf Raise', 1, 'Place the bar on your back') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Calf Raise', 2, 'Start with feet flat on the ground') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Calf Raise', 3, 'Extend your heels upwards while keeping your knees stationary, and pause at the contracted position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Calf Raise', 4, 'Slowly return to the starting position. Repeat.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Footwork Lower And Lift', 1, 'Lie supine, balls of feet on bar, heels lifted.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Footwork Lower And Lift', 2, 'Press bar away, fully extending legs with control.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Footwork Lower And Lift', 3, 'Lower heels under bar, then lift heels as high as possible.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Footwork Lower And Lift', 4, 'Bend knees to return, maintaining steady tension and ankle control.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Running Lying On The Back', 1, 'Lie supine with feet on bar, legs fully extended.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Running Lying On The Back', 2, 'Alternate lowering one heel while the other stays lifted.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Running Lying On The Back', 3, 'Switch rhythmically, maintaining stable pelvis and quiet upper body.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Running Lying On The Back', 4, 'Continue alternating, emphasizing ankle mobility and control.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Squat', 1, 'Stand with your feet shoulder-width apart. Maintain the natural arch in your back, squeezing your shoulder blades and raising your chest.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Squat', 2, 'Grip the bar across your shoulders and support it on your upper back. Unwrack the bar by straightening your legs, and take a step back.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Squat', 3, 'Bend your knees as you lower the weight without altering the form of your back until your hips are below your knees.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Squat', 4, 'Raise the bar back to starting position, lift with your legs and exhale at the top.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Step Up', 1, 'Begin by standing in front of a sturdy box or bench that is about knee-height, holding a barbell across your upper back and shoulders, using an overhand grip.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Step Up', 2, 'Place your right foot on the box and push through the heel to lift your body up and onto the box.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Step Up', 3, 'Step back down with your right foot.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Sumo Deadlift', 1, 'Stance width can vary with a sumo DL. Some prefer toes near the plates. Others prefer a more narrow stance to get more drive off the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Sumo Deadlift', 2, 'Make sure your arms are inside your legs. The bar should be just over your mid-foot. Flatten your back and push your heels into the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Sumo Deadlift', 3, 'Try to extend your knees and hips simultaneously.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell High Bar Squat', 1, 'Place the bar on top of your traps.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell High Bar Squat', 2, 'Push your hips back and break at the knees. Push your elbows forward to keep yourself from getting pitched too far forward.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell High Bar Squat', 3, 'Aim to get your hamstrings to parallel with the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell High Bar Squat', 4, 'Push your heels into the floor and squat back to a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Bulgarian Split Squat', 1, 'Find a box or bench that is roughly knee height or a few inches lower. (The lower the box is the lower the mobility requirement).') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Bulgarian Split Squat', 2, 'You can either place your toes or the top of your foot on the box. Point your front foot forward or slightly turned outwards and break at the knees and hips simultaneously.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Bulgarian Split Squat', 3, 'Aim to get your front leg to hit parallel depth (hamstring parallel with the ground) or lower.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Bulgarian Split Squat', 4, 'The further forward your front foot is, the longer the Range of Motion is at your hips. The further back your front foot is, the longer the ROM at your knees.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Curtsy Lunge', 1, 'Place the barbell on your back') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Curtsy Lunge', 2, 'Step your foot back and around while simultaneously bringing the weight down.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Curtsy Lunge', 3, 'Return to start and repeat on other leg.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Low Bar Squat', 1, 'Pull your shoulder blades back really hard and place the bar on your posterior delts.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Low Bar Squat', 2, 'Push your hips back and break at the knees to initiate the squat.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Low Bar Squat', 3, 'Aim to get your hamstrings to parallel with the ground. Push your heels into the floor and squat back up to a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Squat Bodybuilding', 1, 'Measure your shoulders against the bar to make sure you''re even. Throw your shoulders under the bar. The bar should be digging into your neck slightly.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Squat Bodybuilding', 2, 'Make sure to push your elbows up to the ceiling for the entire rep. To make sure you don''t get too pitched forward.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Squat Bodybuilding', 3, 'Use the squat stance you would use for a back or goblet squat. Push your hips back to initiate the squat. Break at the knees until you hit parallel depth.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Squat Bodybuilding', 4, 'Squat back up to a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Squat Olympic', 1, 'Measure your hands by the markings on the bar to make sure you''re even. Then throw your elbows underneath the bar.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Squat Olympic', 2, 'The bar should be set so high on your shoulders it digs into your neck a bit. Make sure to push your elbows up to the ceiling for the entire rep. To make sure you don''t get too pitched forward.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Squat Olympic', 3, 'Use the squat stance you would use for a back or goblet squat. Push your hips back to initiate the squat. Break at the knees until you hit parallel depth.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Squat Olympic', 4, 'Squat back up to a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Ez Bar Zercher Squat', 1, 'Begin by standing with your feet about hip-width apart and holding the bar in the crook of your arms, near your belly. Your palms should be facing towards your body.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Ez Bar Zercher Squat', 2, 'Sit back and lower your body down until your thighs are parallel to the ground, keeping your back straight and your core engaged.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Ez Bar Zercher Squat', 3, 'Push through your heels to extend your hips and stand back up to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Squat', 1, 'Stand inside trap bar, feet shoulder-width, grip handles.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Squat', 2, 'Sit hips down and back, keeping chest upright.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Squat', 3, 'Lower until thighs are at least parallel.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Squat', 4, 'Push your heels into the floor and squat back to a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Split Squat', 1, 'Take a large step forward with one leg, and lower your body until your back knee nearly touches the ground. Your front knee should be bent at a 90-degree angle, and your back leg should be straight.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Split Squat', 2, 'Push through the heel of your front foot to raise your body back to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Reverse Lunge', 1, 'Stand inside trap bar, grip handles, stand tall.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
