INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Deficit Lunge', 1, 'Stand on a platform, bar on your back, feet hip-width apart.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
