INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Split Squat', 2, 'Push through the heel of your front foot to raise your body back to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Step Up Balance', 1, 'Begin by standing in front of a sturdy box or bench that is about knee-height, holding a barbell across your upper back and shoulders, using an overhand grip.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Step Up Balance', 2, 'Place your right foot on the box and push through the heel to lift your body up and onto the box, keeping your left foot off the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Step Up Balance', 3, 'Step back down with your right foot, lowering your left foot to the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Tap Pause Squat', 1, 'Begin by standing in front of a sturdy box or bench that is about knee-height, holding a barbell across your upper back and shoulders, using an overhand grip.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Tap Pause Squat', 2, 'Sit back and lower your body down until your glutes tap the top of the box, keeping your back straight and your core engaged.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Tap Pause Squat', 3, 'Push through your heels to extend your hips and stand up, bringing your body back to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Zercher Squat', 1, 'Begin by standing with your feet about hip-width apart and holding a barbell in the crook of your arms, near your belly. Your palms should be facing towards your body.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Zercher Squat', 2, 'Sit back and lower your body down until your thighs are parallel to the ground, keeping your back straight and your core engaged.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Zercher Squat', 3, 'Push through your heels to extend your hips and stand back up to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Alternating Lunge And Twist', 1, 'Set up the landmine attachment and load weight.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Alternating Lunge And Twist', 2, 'Stand facing the landmine, holding the weight away from your chest.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Alternating Lunge And Twist', 3, 'Step backward with one leg, lunge down while twisting your torso toward the front leg, return to starting position, and repeat on the other side.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Alternating Lunge To Chest Press', 1, 'Stand facing the landmine with feet hip-width apart and holding the end of the landmine barbell with both hands, keeping elbows bent and close to your body.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Alternating Lunge To Chest Press', 2, 'Step backward with the right foot, lunge down, and press the landmine away from your chest.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Alternating Lunge To Chest Press', 3, 'Push through the left heel to return to the starting position while pulling the landmine back to your chest.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Alternating Lunge To Chest Press', 4, 'Repeat on the opposite side, alternating for the desired number of reps.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Curtsy Lunge', 1, 'Stand facing the barbell while holding the end of the bar at your side with one hand.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Curtsy Lunge', 2, 'With the leg on the same side of your body as the barbell, lunge backward and across your body at a 45 degree angle while keeping your weight on your front heel to lower your back knee gently to the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Curtsy Lunge', 3, 'Drive through your front heel as you step back to the starting position, and repeat for the desired number of reps before switching sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Goblet Curtsy Lunge', 1, 'Start facing the barbell while holding the end of the bar in the goblet position in front of your chest with your elbows close to your sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Goblet Curtsy Lunge', 2, 'Step backward and across your body with one leg at a 45 degree angle while keeping your weight on your front heel to gently lower your back knee to the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Goblet Curtsy Lunge', 3, 'Drive through your front heel as you step back up and to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Goblet Curtsy Lunge', 4, 'Repeat for the desired number of reps before switching legs.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Goblet Lateral Lunge', 1, 'Start facing the barbell while holding the end of the bar close to your chest in the goblet position with your elbows tucked in close to your body.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Goblet Lateral Lunge', 2, 'Step directly out to the side with both toes pointing forward. Keep your weight on the heel of the leg you step out with as you sink down over that foot while your other leg remains straight for balance.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Goblet Lateral Lunge', 3, 'Drive through the heel over which you have centered your body as you step back to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Goblet Lateral Lunge', 4, 'Repeat for the desired number of reps before switching sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Hack Squat', 1, 'Start facing away from the landmine attachment with the end of the barbell resting on one shoulder against the base of your neck while leaning slightly back into the weight of the barbell.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Hack Squat', 2, 'Squat down with control while keeping the weight of the barbell as close to centered over your midpoint as possible, then drive through your heels to stand all the way back up and return to starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Hack Squat', 3, 'Repeat for desired number of reps, then switch the side of your body the barbell is on every subsequent set.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Lateral Lunge', 1, 'Stand facing the landmine with your feet shoulder width apart while holding the end of the barbell in your hands with your arms fully extended down towards the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Lateral Lunge', 2, 'While keeping your torso tall and core engaged, step directly out to one side, using the foot you have stepped out with to sit down into the lunge while keeping your other leg straight.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Lateral Lunge', 3, 'Drive through your heel on your bent leg as your step together to return to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Lateral Lunge', 4, 'Repeat for desired number of reps on the same side before switching sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Lunge', 1, 'Stand in front of the landmine with your feet hip-width apart and your back straight. Grasp the landmine barbell with one hand, holding it at at your side with your palm facing in towards your leg.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Lunge', 2, 'Take a step backward with your foot on the same side that you''re holding the barbell, lowering your body into a lunge position. Bend both knees to lower your body down until your front thigh is parallel to the ground, or as low as your flexibility allows. Keep your torso upright, your chest lifted, and your core engaged throughout the movement.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Lunge', 3, 'Push through the heel of your front foot to return to the starting position. Repeat for desired number of reps before switching sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Lunge To Overhead Press', 1, 'Stand facing the landmine attachment while holding the end of the bar with one hand at your shoulder on the same side with your elbow tucked to your body underneath your wrist.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Lunge To Overhead Press', 2, 'Step back with the leg on the same side that you are holding the bar on and with control lower yourself down into a lunge position while keeping your core engaged and torso tall, then drive through your front heel as you step back to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Lunge To Overhead Press', 3, 'Once your feet are back in the starting position, drive the bar up overhead until your arm is fully extended, then lower the bar back down to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Lunge To Overhead Press', 4, 'Repeated for the desired number of reps, then switch sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Rotational Lift To Press', 1, 'Stand perpendicularly to the barbell with the end of the bar in front of your feet. Squat down and hold the end of the bar with your hand closer to the landmine attachment with your palm facing your body.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Rotational Lift To Press', 2, 'Drive your feet into the ground to start the motion. As your legs fully extend, pull the bar upwards with your hand and start to rotate your torso in towards the landmine attachment. As you do so, bring your other hand up to the bar and switch your grip. Press through the bar to extend your arm all the way upright, pivoting your back foot to allow for more trunk rotation.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Rotational Lift To Press', 3, 'Perform the movement in reverse to return to the starting position. Repeat for desired number of reps before switching sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Landmine Sissy Squat', 1, 'Hold the bar in a goblet position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Landmine Sissy Squat', 2, 'Stand tall, push your knees forward until your calves touch your hamstrings.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Landmine Sissy Squat', 3, 'Make sure to keep your hips extended.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
