INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Sumo Deadlift', 2, 'Bend at the hips and knees, and grab the bar.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Sumo Deadlift', 3, 'Stand up with the bar.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
