INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Thruster', 2, 'Push your hips back and sink into a squat.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Thruster', 3, 'Push through your heels and squat back up. Use the momentum you generate at the legs to push the bar over head.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Thruster', 4, 'Let the bar return to the goblet position before starting the next rep.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Squat With Straps', 1, 'Measure your shoulders against the bar to make sure you''re even. Wrap a pair of lifting straps around the bar. Hold the ends of the straps. Throw your shoulders under the bar. The bar should be digging into your neck slightly.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Squat With Straps', 2, 'Make sure to push your elbows up to the ceiling for the entire rep. To make sure you don''t get too pitched forward.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Squat With Straps', 3, 'Use the squat stance you would use for a back or goblet squat. Push your hips back to initiate the squat. Break at the knees until you hit parallel depth.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Squat With Straps', 4, 'Squat back up to a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Kickstand Squat', 1, 'Stand with feet hip-width apart, one foot slightly behind. Bar on your back.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Kickstand Squat', 2, 'Lower into a squat, keeping weight on front heel.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Kickstand Squat', 3, 'Return to standing, engaging glutes and core.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Quad Stomp', 1, 'Have the barbell in a high bar position and place your foot on a plate or a low box.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Quad Stomp', 2, 'Put all of your weight on your front foot and lean forward.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Quad Stomp', 3, 'Lower until your calves touch your hamstrings and then extend back up.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Rack Deficit Lunge', 1, 'Stand on a platform, barbell in front rack, feet hip-width apart.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Rack Deficit Lunge', 2, 'Step back, lowering knee toward floor, keeping chest upright and core engaged.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Front Rack Deficit Lunge', 3, 'Push through front foot, return to start, keeping bar stable throughout.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Curtsy Deficit Lunge', 1, 'Stand on a platform, barbell on your back, feet hip-width apart.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Curtsy Deficit Lunge', 2, 'Step back, lowering knee toward floor, keeping chest upright and core engaged.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Curtsy Deficit Lunge', 3, 'Push through front foot, return to start, keeping bar stable throughout.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Bulgarian Split Squat', 1, 'Find a box or bench that is roughly knee height or a few inches lower. (The lower the box is the lower the mobility requirement).') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Bulgarian Split Squat', 2, 'You can either place your toes or the top of your foot on the box. Point your front foot forward or slightly turned outwards and break at the knees and hips simultaneously.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Bulgarian Split Squat', 3, 'Aim to get your front leg to hit parallel depth (hamstring parallel with the ground) or lower.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Bulgarian Split Squat', 4, 'The further forward your front foot is, the longer the Range of Motion is at your hips. The further back your front foot is, the longer the ROM at your knees.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Glute Bridge', 1, 'Lay flat on the ground with both feet planted. Make sure you keep your heels glued to the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Glute Bridge', 2, 'Place the dumbbell on your hips. Push your hips toward the ceiling until you feel your glutes contract.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Glute Bridge', 3, 'Then return to the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Goblet Squat', 1, 'Hold the weight tucked into your upper chest area, keeping your elbows in. Your feet should be slightly wider than shoulder width.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Goblet Squat', 2, 'Sink down into the squat, keeping your elbows inside the track of your knees.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Goblet Squat', 3, 'Push through your heels while keeping your chest up and return to starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Goblet Lateral Lunge', 1, 'Engage your core by drawing your belly button towards your spine. This will help to stabilize your body. Hold a dumbbell in a goblet position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
