INSERT INTO step (workout_name, step_number, step_description) VALUES ('Quads Stretch Variation One', 1, 'Stand perpendicular to a wall, using one arm against the wall for balance. With your other arm, grab the top of your foot.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
