INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Leg Press', 3, 'Lower the weight until your legs are at a 90° angle (but DO NOT allow your butt and lower back to rise off of the floor. This will put your lower back in a rounded position, which is very dangerous.)') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
