INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Split Squat', 1, 'Take a large step forward with one leg until your shoulders are under the smith machine') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Split Squat', 2, 'lower your body until your back knee nearly touches the ground. Your front knee should be bent at a 90-degree angle, and your back leg should be straight.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Split Squat', 3, 'Push through the heel of your front foot to raise your body back to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Reverse Lunge', 1, 'Start by standing with your feet about hip-width apart, with the bar on your shoulders. Your feet should be slightly pointed outward, and your shoulders should be down and relaxed.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Reverse Lunge', 2, 'Step backward with one foot, lowering your body until your front thigh is parallel to the ground and your back knee is hovering just above the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Reverse Lunge', 3, 'Push off your back foot, returning to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Narrow Stance Squat', 1, 'Place the bar on top of your traps. Take a narrow stance.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Narrow Stance Squat', 2, 'Push your hips back and break at the knees. Push your elbows forward to keep yourself from getting pitched too far forward.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Narrow Stance Squat', 3, 'Aim to get your hamstrings to parallel with the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Narrow Stance Squat', 4, 'Push your heels into the floor and squat back to a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Single Leg Bicycle', 1, 'Lie supine, one knee bent, opposite leg extended.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Single Leg Bicycle', 2, 'Press through one leg. Simultaneously pull the raised leg up to a table top position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Single Leg Bicycle', 3, 'As you lower, bring your non-working leg back into extension.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Single Leg One Leg Bent', 1, 'Lie supine, one foot planted, opposite leg in a tabletop position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Single Leg One Leg Bent', 2, 'Engage core, maintain neutral pelvis.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Footwork High Half Toe', 1, 'Lie supine, balls of feet on bar, heels lifted high.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Footwork High Half Toe', 2, 'Press bar away, extending legs while maintaining lifted heels.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Footwork High Half Toe', 3, 'Keep pelvis neutral, ribs down, and core engaged.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Footwork High Half Toe', 4, 'Bend knees to return smoothly, maintaining ankle stability and control.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Footwork Heels On The Bar', 1, 'Lie supine, heels on bar hip-width, toes lifted slightly.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Footwork Heels On The Bar', 2, 'Press bar away, fully extending legs without locking knees.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Footwork Heels On The Bar', 3, 'Maintain neutral pelvis, ribs down, and steady core engagement.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Footwork Heels On The Bar', 4, 'Bend knees to return with control, keeping heels connected.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Hip Rolls', 1, 'Lie supine with knees bent, feet hip-width, arms relaxed by sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Hip Rolls', 2, 'Inhale to prepare, exhale and posteriorly tilt pelvis.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Hip Rolls', 3, 'Roll spine up one vertebra at a time into bridge.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Hip Rolls', 4, 'Press through legs until legs are nearly extended. Lower back to start.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Hip Rolls', 5, 'Then begin rolling your spine downward until your back is flat against the carriage.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Hip Lift', 1, 'Lie supine with knees bent, feet hip-width and flat. Hips slightly off the carriage.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Hip Lift', 2, 'Engage core and glutes, press through heels.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Hip Lift', 3, 'Maintain hip position as you press.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pilates Short Spine', 1, 'Lie supine, feet in straps, legs extended upward.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pilates Short Spine', 2, 'Lift hips, rolling spine off carriage.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pilates Short Spine', 3, 'Bend knees, bringing heels toward glutes overhead.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pilates Short Spine', 4, 'Roll down slowly, extending legs to start.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pilates Footwork First Position', 1, 'Lie on reformer, heels together, toes apart on footbar.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pilates Footwork First Position', 2, 'Press carriage out by extending legs evenly.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pilates Footwork First Position', 3, 'Keep pelvis stable and core engaged.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pilates Footwork First Position', 4, 'Bend knees to return with control.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pilates Single Leg Heel', 1, 'Lie on reformer, one heel on footbar, other leg extended.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pilates Single Leg Heel', 2, 'Press carriage out using working leg.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pilates Single Leg Heel', 3, 'Keep hips level and core engaged.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pilates Single Leg Heel', 4, 'Bend knee to return with control.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Roll Outs', 1, 'Hold the Barbell with both hands and kneel on the floor with your feet up') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Roll Outs', 2, 'Slowly roll the Barbell straight forward, stretching your body into a straight position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Roll Outs', 3, 'After a pause at the stretched position, start pulling yourself back to the starting position. This should be a slow and controlled movement.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Situp', 1, 'Hold the bar with a slightly wider than shoulder width grip. Push the bar up toward the ceiling and maintain that elbow extension.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Situp', 2, 'Flex your abs and sit-up. Aim to get your torso vertical while maintaining the barbell overhead.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Sit Up', 1, 'Lay flat on the ground and hold the end of the bar with your arms extended.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Sit Up', 2, 'Raise your back off the ground until you are sitting at a 90 degree angle.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Sit Up', 3, 'Then lower slowly back to the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Hollow Hold', 1, 'Start by lying flat on your back with your legs extended towards the landmine attachment and your arms overhead, holding the landmine barbell with both hands while engaging your core muscles by pressing your lower back into the ground and drawing your belly button in towards your spine.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Hollow Hold', 2, 'Lift your legs off the ground, keeping them together and straight, and simultaneously raise your upper body off the ground, reaching the landmine barbell away from your face.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Hollow Hold', 3, 'Hold this position for the desired duration, then carefully lower the barbell to the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Larsen Bench Press', 1, 'Start in a bench press position with your legs elevated. Try to keep your knees with a slight bend in them.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Larsen Bench Press', 2, 'Unrack the bar then initiate the rep.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Larsen Bench Press', 3, 'Bring the bar to your torso and tap your ribcage before pressing back to the ceiling.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Hooklying Bench Press', 1, 'Start in a bench press position with your feet planted on the bench and knees bent.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Hooklying Bench Press', 2, 'Grasp the barbell with an overhand grip, positioning your hands slightly wider than shoulder-width apart.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Hooklying Bench Press', 3, 'Lift the barbell off the rack and lower it to your chest, keeping your elbows close to your sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Hooklying Bench Press', 4, 'Push the barbell back up to the starting position, fully extending your arms.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Russian Twist', 1, 'Sit on the floor and flex your knees and hips to a 90 degree angle.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Russian Twist', 2, 'Your feet should be hovering off the ground. (If that''s too hard start with heels on the floor)') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Russian Twist', 3, 'Rotate your upper spine to engage your obliques.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Situp', 1, 'Lay flat on the ground with your spine neutral. Extend you arms so your fists are pointed at the ceiling.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Situp', 2, 'Sit-up by flexing your abs. Continue to reach for the ceiling for the entire rep.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Plank Pullthrough', 1, 'Get into a plank position. Either from your knees or toes.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Plank Pullthrough', 2, 'Start with the DB by your right hand. Reach with your left and pull the dumbbell to your left arm. Then repeat with the right.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Hollow Hold', 1, 'Lay flat on the ground with a dumbbell overhead.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Hollow Hold', 2, 'Pull your upper back and legs off the ground. Make a banana shape with your body.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Hollow Hold', 3, 'The dumbbell should be held in your hands and your ears should be between your biceps.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Crunch', 1, 'Start by lying flat on your back with your feet flat on the floor and your knees bent.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Crunch', 2, 'Hold a dumbbell over your clavicle.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Crunch', 3, 'Engage your core muscles and lift your torso off the floor until your shoulders are a few inches off the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Crunch', 4, 'Lower yourself back down to the starting position, but avoid resting completely on the floor between reps.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Plank IYTW', 1, 'Start in a plank position. Hold one dumbbell.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Plank IYTW', 2, 'Raise the dumbbell straight out in front of you (I), at a 45 degree angle (Y), out to the side (T), and then bend at the elbow while raising (W).') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Plank IYTW', 3, 'Going through IYTW counts as one rep.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Plank IYTW', 4, 'Make sure to keep your hips stable. If you''re unable to, try performing this exercise from the knees.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Suitcase Crunch', 1, 'Lay flat on the ground with a dumbbell. Point the soles of your shoes at the ceiling as well as the dumbbell.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Suitcase Crunch', 2, 'Reach for your feet with the dumbbell before bringing your spine back to the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Half Kneeling Wood Chopper', 1, 'Take a half kneeling position. Start with the dumbbell by your knee on the side of the kneeling leg.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Half Kneeling Wood Chopper', 2, 'Rotate at the upper spine, holding the dumbbell away from your body with nearly extended elbows.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Renegade Row', 1, 'Start by getting into a plank position with a dumbbell in each hand. Your feet should be shoulder-width apart and your hands should be placed on the dumbbells, with your palms facing each other.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Renegade Row', 2, 'From this starting position, row one dumbbell up towards your chest, keeping your elbow close to your body and your core engaged.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Renegade Row', 3, 'Slowly lower the dumbbell back down to the starting position, and repeat on the other side.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Renegade Row', 4, 'Make sure to keep your body straight and your hips level throughout the movement.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pushup to Renegade Row', 1, 'Start in a high plank position with a pair of dumbbells positioned under your shoulders. Your hands should grip the dumbbells, palms facing each other.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pushup to Renegade Row', 2, 'Keep your core engaged and your back straight as you row one dumbbell up towards your hip, keeping your elbow close to your body.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pushup to Renegade Row', 3, 'Lower the dumbbell back down to the starting position and repeat on the other side.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Larsen Press', 1, 'Lie on bench with feet off floor, holding dumbbells above chest.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Larsen Press', 2, 'Lower dumbbells toward chest while keeping legs elevated and torso stable.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Larsen Press', 3, 'Press upward, squeezing chest at the top without arching lower back.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Single Arm Larsen Press', 1, 'Lie on bench with feet off floor, holding one dumbbell above chest.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Single Arm Larsen Press', 2, 'Lower dumbbell toward chest while keeping core tight and legs raised.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Single Arm Larsen Press', 3, 'Press upward, squeezing chest at the top without twisting torso.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Crunches', 1, 'Lay flat on your back with your knees bent and your feet flat on the ground, about a foot from your lower back.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Crunches', 2, 'Place your fingertips on your temples with your palms facing out.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Crunches', 3, 'Draw your belly into the base of your spine to engage the muscles, then raise your head and shoulders off the floor. Return to starting position and repeat.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Laying Leg Raises', 1, 'Lay on your back with your arms palms down on either side.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Laying Leg Raises', 2, 'Keep your legs together and as straight as possible.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Laying Leg Raises', 3, 'Slowly raise your legs to a 90° angle, pause at this position, or as high as you can reach your legs, and then slowly lower your legs back down.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Laying Leg Raises', 4, 'Duration of these movements should be slow so that you do not utilize momentum, enabling you to get the most out of the exercise.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Long Lever Plank', 1, 'Start in a hand plank position and walk your hands further out until your ears are between your biceps.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Long Lever Plank', 2, 'Hold in this position for the allotted amount of time.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Long Lever Plank', 3, 'Make sure you keep a flat back for the whole set.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Hanging Knee Raises', 1, 'Grab the bar and hang, your body still and your legs straight.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Hanging Knee Raises', 2, 'Slowly draw your knees up to your chest') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Hanging Knee Raises', 3, 'Once you have raised your knees as high as possible, lower your legs and repeat. Duration of these movements should be slow so that you do not utilize momentum, enabling you to get the most out of the exercise.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Hanging Knee Raises', 4, 'Duration of these movements should be slow so that you do not utilize momentum, enabling you to get the most out of the exercise.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Forearm Plank', 1, 'Place forearms on the ground with your elbows bent at a 90° angle aligned beneath your shoulders, with your arms parallel at shoulder-width.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Forearm Plank', 2, 'Your feet should be together, with only your toes touching the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Forearm Plank', 3, 'Lift your belly off the floor and form a straight line from your heels to the crown of your head and hold.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Bodyweight Hand Plank Jack', 1, 'Start in high plank, hands under shoulders, body straight.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Bodyweight Hand Plank Jack', 2, 'Jump hands outward simultaneously while keeping feet planted and core tight.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Bodyweight Hand Plank Jack', 3, 'Jump hands back under shoulders, maintaining stable hips and spine.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Bodyweight Feet Plank Jack', 1, 'Start in high plank, hands under shoulders, body straight.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Bodyweight Feet Plank Jack', 2, 'Jump feet out wide while bracing core and keeping hips level.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
