INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Hand Side Plank', 1, 'Start by lying on your side with your feet stacked on top of each other and a dumbbell on your hip.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
