INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Elbow Side Plank', 1, 'Take an elbow side plank position. Place a dumbbell on your hip.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
