INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Long Lever Russian Twist', 3, 'Continue this twisting motion, alternating sides, for the desired number of repetitions. Keep your core engaged and avoid swinging your arms to generate momentum.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
