INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Bicep Curl', 3, 'Repeat for the desired number of reps before switching sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Supinated Row', 1, 'Begin by standing in front of a barbell with your feet about hip-width apart.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
