INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Supinated Row', 4, 'As the barbell reaches your chest, pause briefly, and then lower the barbell back to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Supinated Pendlay Row', 1, 'Begin by standing in front of a barbell with your feet about hip-width apart and your palms facing towards your body.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Supinated Pendlay Row', 2, 'Bend at the hips and knees to grab the barbell with a pronated (overhand) grip, positioning the barbell about an inch away from your shins.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Supinated Pendlay Row', 3, 'Keeping your back straight and your core engaged, use your back muscles to lift the barbell straight up towards your chest.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Supinated Pendlay Row', 4, 'As the barbell reaches your chest, rotate your wrists so that your palms are facing towards your body (supinated grip), and then lower the barbell back to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
