INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Pronated Pendlay Row', 2, 'Pull the bar to your sternum.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Pronated Pendlay Row', 3, 'Return the plates back to the floor and let the bar come to a full dead stop.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Pronated Pendlay Row', 4, 'Then initiate the next rep.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
