INSERT INTO step (workout_name, step_number, step_description) VALUES ('Downward Dog With Fingers Facing Feet', 6, 'Hold the pose for several breaths, then release and return to your starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
