INSERT INTO step (workout_name, step_number, step_description) VALUES ('Pilates Back Rowing Seated Row', 1, 'Sit tall, legs extended, hold straps with arms forward.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
