INSERT INTO step (workout_name, step_number, step_description) VALUES ('Traps Stretch Variation Three', 1, 'Stand upright with your feet shoulder width apart.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Traps Stretch Variation Three', 2, 'Nod your head forward, bringing your chin to your chest.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Traps Stretch Variation Three', 3, 'You will feel the stretch across your neck.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Cable Silverback Shrug', 1, 'Use a bar attachment. Cable should be set all the way to the bottom.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
