INSERT INTO step (workout_name, step_number, step_description) VALUES ('Cable Silverback Shrug', 3, 'Retract your shoulder blades and then protract to return to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Cable 30 Degree Shrug', 1, 'Use a handle attachment on both sides of crossover. With cable attachment set all the way to the bottom.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Cable 30 Degree Shrug', 2, 'Grab both handles and make sure you are centered in the machine. Let your arms hang freely.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Cable 30 Degree Shrug', 3, 'Pull your shoulder blades up and in towards your ears. Let your shoulder blades depress back to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Cable Single Arm 30 Degree Shrug', 1, 'Use a handle attachment. With the cable attachment set all the way to the bottom.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Cable Single Arm 30 Degree Shrug', 2, 'Grab one handle and make sure you are centered in the machine. Let your arm hang freely.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Cable Single Arm 30 Degree Shrug', 3, 'Pull your shoulder blade up and in towards your ears. Let your shoulder blade depress back to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Band Shrug', 1, 'Place the band under your feet. Stand upright.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Band Shrug', 2, 'Elevate your shoulder blades and then depress back to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Band Horizontal Shrug', 1, 'Anchor the band at shoulder height. Take a few steps away until the band is taut.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Band Horizontal Shrug', 2, 'Retract your shoulder blades straight back in schools. Then protract to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Plate Overhead Shrug', 1, 'Stand tall with a weight plate overhead.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Plate Overhead Shrug', 2, 'Elevated and depress your scapula.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Plate Overhead Shrug', 3, 'Avoid leaning forward or backwards to keep pressure off of your lumbar spine.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Criss Cross Bow Tie Pose', 1, 'Stand with your feet hip-width apart and your arms at your sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Criss Cross Bow Tie Pose', 2, 'Cross your right arm over your left arm, bringing your palms together in front of your chest.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Criss Cross Bow Tie Pose', 3, 'Lower your arms down so that your palms face down towards the ground, and your right elbow is resting on top of your left elbow.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Criss Cross Bow Tie Pose', 4, 'Hold for a few breaths, then switch sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Eagle Arms Chin Into Chest', 1, 'Sit cross-legged on the floor and bring your arms out to the sides at shoulder height.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Eagle Arms Chin Into Chest', 2, 'Cross your right arm over your left, bending both elbows so that your forearms are parallel to the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Eagle Arms Chin Into Chest', 3, 'Lift your elbows towards the ceiling and bring your hands together, then drop your chin towards your chest.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Eagle Arms Chin Into Chest', 4, 'Hold for a few breaths, then release your arms and repeat on the other side.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Easy Pose Neck Stretch', 1, 'Begin by sitting cross-legged on the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Easy Pose Neck Stretch', 2, 'Slowly drop your chin towards your chest, feeling a stretch in the back of your neck.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Easy Pose Neck Stretch', 3, 'Inhale and lift your head up, then exhale and drop your right ear towards your right shoulder.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Easy Pose Neck Stretch', 4, 'Hold for a few breaths, then switch sides and repeat the stretch.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Half Neck Rolls', 1, 'Sit cross-legged on the floor and interlace your fingers behind your head.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Half Neck Rolls', 2, 'Drop your chin to your chest and roll your head to the right, bringing your right ear towards your right shoulder.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Half Neck Rolls', 3, 'Slowly roll your head back to center, then over to the left so that your left ear is close to your left shoulder.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Half Neck Rolls', 4, 'Repeat the movement from side to side, keeping your shoulders relaxed and breathing deeply.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Thread The Needle Hip Over Knees', 1, 'Start on your hands and knees in a tabletop position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Thread The Needle Hip Over Knees', 2, 'Slide your right knee up between your hands and place your right foot close to your left wrist.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Thread The Needle Hip Over Knees', 3, 'Take your left leg back and lower it down to the ground, keeping your toes tucked.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Thread The Needle Hip Over Knees', 4, 'Twist your torso to the right and reach your right arm underneath your left arm, threading the needle. Hold for a few breaths, then switch sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Bosu Ball Pike Shrug', 1, 'Place toes on Bosu, hands on the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Bosu Ball Pike Shrug', 2, 'Pike hips up, shrug shoulders, engage core.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Romanian Deadlift', 1, 'Take a shoulder width, double overhand or mixed grip.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Romanian Deadlift', 2, 'Push your hips back while leaving your knees mostly extended. Look for a stretch in your hamstrings.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Romanian Deadlift', 3, 'When you feel the stretch, push your hips forward until you''re back in a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Stiff Leg Deadlifts', 1, 'Stand with a barbell at your shins with your feet shoulder width apart.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Stiff Leg Deadlifts', 2, 'Bend forward at your hips and keep your knees as fully extended as possible.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Stiff Leg Deadlifts', 3, 'Grab the barbell and then extend your hips while maintaining a straight back.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Stiff Leg Deadlifts', 4, 'From the standing position, lower the weight in a controlled manner.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Stiff Leg Deadlifts', 5, 'You can either lower the weight to the floor or before you touch the floor, depending on your mobility.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Staggered Deadlift', 1, 'Place one foot behind. You should only be on your toes on that back foot. Your front foot should be planted flat the entire time.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Staggered Deadlift', 2, 'Bend your back knee and push your hips back. Look for a stretch in your front hamstring.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Staggered Deadlift', 3, 'When you feel the stretch, push your hips forward again until you''re back in a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Low Bar Good Morning', 1, 'Place the bar between your traps and rear delts. Pull your shoulder blades back to give the bar a shelf to sit on.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Low Bar Good Morning', 2, 'Push your hips back until you feel a stretch in your hamstrings. This means you''re nearing the end of your Range of Motion with out rounding your spine.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Low Bar Good Morning', 3, 'When you feel the stretch push your hips forward until you''e in a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell High Bar Good Morning', 1, 'Place the bar on your traps. You may need a pad so the bar doesn''t dig into your cervical spine.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell High Bar Good Morning', 2, 'Push your hips straight back. Your knees should stay MOSTLY extended (think soft knees). Also make sure to') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell High Bar Good Morning', 3, 'Look for what feels like a stretch in your hamstrings. The stretch feeling means you''re likely nearing the end of your Range of Motion without rounding your spine.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell High Bar Good Morning', 4, 'When you feel the stretch push your hips forward until you''re in a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Single Leg Deadlift', 1, 'Start by pushing your hips straight back and extending your non-working leg behind you. It is ok to touch your other foot back to the ground each rep.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Single Leg Deadlift', 2, 'Leave your knee mostly extended. Look for a stretch in your hamstring. When you feel the stretch, push your hips forward until you''re back in a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Snatch Grip Deadlift', 1, 'Start by standing with your feet about hip-width apart, with your toes pointed slightly outward.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Snatch Grip Deadlift', 2, 'Place a barbell on the floor in front of you, with the weight plates on either side. Make sure that the bar is directly in line with your feet.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Snatch Grip Deadlift', 3, 'Bend down and grab the barbell with an overhand grip, your hands much wider than shoulder-width apart. Keep your back straight and your shoulders down as you grip the bar.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Snatch Grip Deadlift', 4, 'Stand up straight, lifting the barbell off the ground and pulling it toward your hips. Keep your elbows close to your body and your shoulders down as you do this.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Snatch Grip Deadlift', 5, 'Slowly lower the barbell back to the ground, making sure to keep your back straight and your shoulders down throughout the movement.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Snatch Grip Romanian Deadlift', 1, 'Start by standing with your feet about hip-width apart. The bar should be in a rack or box so it''s lifted off the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Snatch Grip Romanian Deadlift', 2, 'Grab the barbell with an overhand grip, your hands should be much wider than shoulder-width apart.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Snatch Grip Romanian Deadlift', 3, 'Hing forward at the hips keeping your knees mostly extended. Hinge until you feel a stretch in your hamstrings.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Snatch Grip Romanian Deadlift', 4, 'When you feel the stretch, push your hips forward until you are back in a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Zercher Good Morning', 1, 'Begin by standing with your feet about hip-width apart and holding a barbell in the crook of your elbows, with your palms facing towards your body.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Zercher Good Morning', 2, 'Keeping your core engaged and your back straight, bend at the hips and lower your torso forward until it is nearly parallel to the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Zercher Good Morning', 3, 'Push through your heels to extend your hips and raise your body back to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Romanian Deadlift', 1, 'Stand in front of the landmine with your feet hip-width apart and your knees slightly bent. Grasp the landmine barbell with both hands, palms facing each other, and hold it in front of your thighs.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Romanian Deadlift', 2, 'Keeping your back straight and your core engaged, hinge at the hips and push your hips back, allowing the landmine to travel down your thighs. Lower the landmine by bending forward at the hips while keeping your back flat, allowing the barbell to move closer to the floor. Continue the movement until you feel a stretch in your hamstrings, keeping your legs relatively straight but with a slight bend in the knees.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Romanian Deadlift', 3, 'Reverse the movement by pushing your hips forward and driving through your heels while keeping your back straight.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Romanian Deadlift', 4, 'Repeat for the desired number of reps.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Single Leg Romanian Deadlift', 1, 'Grab the end of the landmine and stand perpendicular to the bar.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Single Leg Romanian Deadlift', 2, 'Lift your inside leg and keep your outside leg planted.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Single Leg Romanian Deadlift', 3, 'Push your hips back keeping your knees mostly extended. When you feel the stretch in your hams, push your hips forward until you are standing upright.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Staggered Romanian Deadlift', 1, 'Stand in a staggered position. With the back leg bent and the front mostly extended.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Staggered Romanian Deadlift', 2, 'Push your hips back until you feel a stretch through your front hamstring.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Staggered Romanian Deadlift', 3, 'Push your hips back forward until you are standing.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Banded Romanian Deadlift', 1, 'Loop bands under your feet or anchors and around the barbell. Stand tall with soft knees.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Banded Romanian Deadlift', 2, 'Hinge at the hips, keeping the bar close and back straight throughout.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Barbell Banded Romanian Deadlift', 3, 'Squeeze glutes, drive hips forward, and return to full standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Ez Bar Romanian Deadlift', 1, 'Take a shoulder width, double overhand or mixed grip.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Ez Bar Romanian Deadlift', 2, 'Push your hips back while leaving your knees mostly extended. Look for a stretch in your hamstrings.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Ez Bar Romanian Deadlift', 3, 'When you feel the stretch, push your hips forward until you''re back in a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Romanian Deadlift', 1, 'Hold trap bar, stand tall with slight knee bend.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Romanian Deadlift', 2, 'Hinge hips back, lowering bar along thighs.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Romanian Deadlift', 3, 'Keep back neutral and tension in hamstrings.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Romanian Deadlift', 4, 'Drive hips forward to return upright.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Staggered Romanian Deadlift', 1, 'Stand inside trap bar. Place one foot behind. You should only be on your toes on that back foot. Your front foot should be planted flat the entire time.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Staggered Romanian Deadlift', 2, 'Bend your back knee and push your hips back. Look for a stretch in your front hamstring.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Staggered Romanian Deadlift', 3, 'When you feel the stretch, push your hips forward again until you''re back in a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Single Leg Deadlift', 1, 'Stand inside trap bar, lift one foot slightly off ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Single Leg Deadlift', 2, 'Hinge hips back while lowering bar and extending free leg behind.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Single Leg Deadlift', 3, 'Keep hips square and back neutral throughout movement.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Trap Bar Single Leg Deadlift', 4, 'Drive through standing foot to return upright.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Romanian Deadlift', 1, 'Stand with a shoulder width stance. Push your butt back while leaving your knees MOSTLY extended.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Romanian Deadlift', 2, 'You should feel a stretch in your hamstrings. When you feel the stretch, push your hips forward to complete the rep.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Romanian Deadlift', 3, 'Do not push your hips all the way forward. This will hyperextend your spine. Just go to a normal standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Goblet Good Morning', 1, 'Hold the dumbbell in a goblet position. With your elbows directly under your fists.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Goblet Good Morning', 2, 'Push your hips back while leaving your knees MOSTLY extended. You should feel a stretch in your hamstrings.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Goblet Good Morning', 3, 'When you feel the stretch push your hips forward until you''re back in a standing position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Leg Curl', 1, 'Lay flat on a bench with a dumbbell between your feet.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Leg Curl', 2, 'Flex your knees and raise the dumbbell until the soles of your shoes are pointed at the ceiling.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Single Leg Single Arm Deadlift', 1, 'Start by standing on one leg with a dumbbell in one hand.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Single Leg Single Arm Deadlift', 2, 'Slowly bend at the hips and lower the dumbbell towards the ground while extending your free leg behind you.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Single Leg Single Arm Deadlift', 3, 'Keep your core engaged and your back straight as you lower the weight.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Single Leg Single Arm Deadlift', 4, 'Once the dumbbell is close to the ground, push through your heel to return to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Single Leg Stiff Leg Deadlift', 1, 'Start by standing on one leg with your feet shoulder-width apart and holding two dumbbells.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
