INSERT INTO step (workout_name, step_number, step_description) VALUES ('Warrior Three', 1, 'Start in mountain pose, standing with your feet hip-width apart and arms at your sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
