INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Staggered Deadlift', 1, 'Place one foot behind. You should only be on your toes on that back foot. Your front foot should be planted flat the entire time.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
