INSERT INTO step (workout_name, step_number, step_description) VALUES ('Smith Machine Sumo Romanian Deadlift', 1, 'Stance width can vary with a sumo DL. Some prefer toes near the plates. Others prefer a more narrow stance to get more drive off the floor.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
