INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Single Arm Staggered Overhead Press', 1, 'Stand facing the bar in a split stance with one leg forward and bent and the other back and straight. Hold the bar in the hand on the side of the leg that is back with the end of the bar at your shoulder with your elbow tucked beneath your hand.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Single Arm Staggered Overhead Press', 2, 'Drive the bar upwards until your arm is fully extended. Pause briefly before lowering the end of the bar back down to the starting position with control.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Single Arm Staggered Overhead Press', 3, 'Repeat for the desired number of reps before switching sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Single Arm Push Press', 1, 'Stand in front of the landmine with your feet shoulder-width apart and your knees slightly bent. Grasp the landmine barbell with one hand, palm facing in, and bring it to shoulder height with your elbow tucked beneath your hand.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Single Arm Push Press', 2, 'Dip your body slightly then drive up through the ground to generate momentum as your extend your arm fully upwards. Pause briefly at the top of the rep, then lower the weight back down to the starting position with control.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Single Arm Push Press', 3, 'Repeat for the desired number of reps on one side before switching sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Single Arm Overhead Press', 1, 'Stand in front of the landmine with your feet shoulder-width apart and your knees slightly bent. Grasp the landmine barbell with one hand, palm facing in, and bring it to shoulder height with your elbow tucked beneath your hand.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Single Arm Overhead Press', 2, 'Press the barbell overhead by extending your arm fully, pushing the weight upward. Keep your core engaged, your back straight, and your shoulder down throughout the movement. Pause briefly at the top of the movement with your arm fully extended overhead. Slowly lower the barbell back to the starting position at shoulder height with control.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Single Arm Overhead Press', 3, 'Repeat for the desired number of reps on one side before switching sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Seated Single Arm Overhead Press', 1, 'Sit on the ground facing the landmine with your legs spread. Hold the end of the bar in one hand in front of that shoulder with your palm facing across your body.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Seated Single Arm Overhead Press', 2, 'While keeping your torso tall and your core braced, drive the bar upwards until your arm is fully extended, leaning forward slightly for full range of motion in the shoulder joint. Lower the bar back down to the starting position with control.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Seated Single Arm Overhead Press', 3, 'Repeat for desired number of reps on one side, then switch sides.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Seated Overhead Press', 1, 'Sit on the ground facing the landmine with your legs spread. Hold the end of the bar in both hands in front of your chest with your palms facing each other.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Seated Overhead Press', 2, 'While keeping your torso tall and core brace, drive the end of the bar upward until your arms are fully extended. Lean forward slightly for full range of motion in the shoulder joints. Lower the bar back down to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Seated Overhead Press', 3, 'Repeat for desired number of reps.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Seated Alternating Overhead Press', 1, 'Start sitting on the ground facing the landmine attachment with your legs open for stability while holding the end of the bar in a neutral grip with your hand resting at your shoulder and your elbow beneath your wrist.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Seated Alternating Overhead Press', 2, 'Leaning forward slightly, press the bar up into the air until your arm is fully extended. At the top of the movement, switch which hand is holding the end of the bar and lower the bar back down to the opposite shoulder. Perform again to return the bar to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Seated Alternating Overhead Press', 3, 'Repeat for the desired number of reps.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Overhead Press', 1, 'Stand facing the landmine, holding the end of the bar in both hands with your palms facing each other.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Overhead Press', 2, 'Extend your arms upward, pressing the end of the bar up overhead. Pause at the top of the movement, then lower the bar with control back to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Overhead Press', 3, 'Repeat for the desired number of reps.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Lying Tricep Extension', 1, 'Start lying on your back perpendicularly to the barbell, holding the bar directly over your shoulder with the hand that''s closer to the bar with your palm facing down towards your feet.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
