INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Kneeling Overhead Press', 1, 'Start kneeling in front of the landmine, facing towards it, with your knees hip-width apart and your back straight while holding the end of the bar in both hands in front of your chest.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Kneeling Overhead Press', 2, 'Push the landmine up overhead by fully extending your arms until the weight is directly over your head. Pause briefly at the top of the movement, then slowly lower the landmine back down to the starting position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Landmine Kneeling Overhead Press', 3, 'Repeat for the desired number of reps.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Dumbbell Skullcrusher', 1, 'Lay flat on the floor or a bench with your fists extended to the ceiling and a neutral grip.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
