INSERT INTO step (workout_name, step_number, step_description) VALUES ('Thoracic Extensions Foam Roller', 4, 'Support head on palms, elbows rotated in. Slightly lift hips off the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Intrascapular Muscle Contraction', 1, 'Stand up straight and keep your shoulders relaxed.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Intrascapular Muscle Contraction', 2, 'Bring your shoulder blades in towards the spine.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Intrascapular Muscle Contraction', 3, 'Rotate palms out to help squeeze the muscles in between the shoulder blades.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Laying Levator Scapulae Mobilisation Massage Ball', 1, 'Lie on your back with knees bent and feet flat on the floor. Keep your arm by your side') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Laying Levator Scapulae Mobilisation Massage Ball', 2, 'Place a massage ball under the area between the top of your scapula and spine with the other arm.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Laying Levator Scapulae Mobilisation Massage Ball', 3, 'Once you find the tight/sore spot, move your arm over your head and back to starting position to mobilise your levator scapula muscle.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Laying Ts', 1, 'Lie on your front, arms outstretched to the side.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Laying Ts', 2, 'Raise head and chest off the ground.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Laying Ts', 3, 'Raise and lower your arms (flapping wings motion) by contracting and relaxing the muscles in between your shoulder blades.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Scapular Depression', 1, 'From the standing or seated position straighten your back.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Scapular Depression', 2, 'Pull the shoulders back but keep them relaxed.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Scapular Depression', 3, 'Move shoulders away from your ears and return to the starting, relaxed position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Scapular Protraction', 1, 'From the standing or seated position straighten your back.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Scapular Protraction', 2, 'Pull the shoulders back but keep them relaxed.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Scapular Protraction', 3, 'Move shoulders forward and return to the starting, relaxed position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Scapular Retraction', 1, 'From the standing or seated position straighten your back.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Scapular Retraction', 2, 'Pull the shoulders back but keep them relaxed.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
INSERT INTO step (workout_name, step_number, step_description) VALUES ('Scapular Retraction', 3, 'Move shoulders backwards and return to the starting, relaxed position.') ON DUPLICATE KEY UPDATE step_description = VALUES(step_description);
